describe('Moodboard Editor Journeys', () => {
  // Generate a mock JWT that won't instantly expire
  // Payload: {"exp": 9999999999, "role": "USER", "sub": "test@example.com"}
  const mockJwt = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJleHAiOjk5OTk5OTk5OTksInJvbGUiOiJVU0VSIiwic3ViIjoidGVzdEBleGFtcGxlLmNvbSJ9.mock-signature';
  // Paste your full base64 image URI here (data:image/jpeg;base64,...) for mock uploads.
  const mockUploadImageData = 'data:image/jpeg;base64,';
  
 
  // Helper: Rotate image by specific degrees using circular arc math
  beforeEach(() => {
    // Set a known viewport for stable canvas coordinates
    cy.viewport(1280, 720);
    
    // Mock APIs to ensure isolation
    cy.intercept('POST', '**/api/auth/login', {
      statusCode: 200,
      body: { accessToken: mockJwt, refreshToken: mockJwt }
    }).as('loginRequest');

    cy.intercept('POST', '**/api/auth/refresh', {
      statusCode: 200,
      body: { accessToken: mockJwt, refreshToken: mockJwt }
    }).as('refreshRequest');

    cy.intercept('GET', '**/api/user/me', {
      statusCode: 200,
      body: { email: 'test@example.com', name: 'Test User' }
    }).as('getUser');

    cy.intercept('GET', '**/api/plans/usage', {
      statusCode: 200,
      body: { usage: { moodboardsUsed: 0, moodboardsLimit: 10 } }
    }).as('getUsage');

    cy.intercept('GET', '**/api/moodboard', {
      statusCode: 200,
      body: []
    }).as('getBoards');

    let mockBoardState = { 
      id: 'mock-board-id', 
      title: "Test Board",
      background: "#ffffff", 
      isPublic: true,
      scene: JSON.stringify({ items: [] })
    };

    // Mocks for creating and fetching a board
    cy.intercept('POST', '**/api/moodboard', (req) => {
      req.reply({
        statusCode: 201,
        body: { id: 'mock-board-id', elements: [] }
      });
    }).as('createBoard');
    
    cy.intercept('PUT', '**/api/moodboard/mock-board-id', (req) => {
      if (typeof req.body === 'object' && !ArrayBuffer.isView(req.body) && !(req.body instanceof ArrayBuffer)) {
        mockBoardState = { ...mockBoardState, ...req.body };
      }
      req.reply({ statusCode: 200, body: mockBoardState });
    }).as('updateBoard');

    cy.intercept('PATCH', '**/api/moodboard/mock-board-id', (req) => {
      if (typeof req.body === 'object' && !ArrayBuffer.isView(req.body) && !(req.body instanceof ArrayBuffer)) {
        mockBoardState = { ...mockBoardState, ...req.body };
      }
      req.reply({ statusCode: 200, body: mockBoardState });
    }).as('patchBoard');

    // Mock image upload endpoint - uses the configured base64 JPEG image.
    cy.intercept('POST', '**/api/moodboard/*/items', {
      statusCode: 201,
      body: { src: mockUploadImageData }
    }).as('uploadItem');
    
    // Make sure GET always returns "My UI Test Board" for Journey 1 verification
    cy.intercept('GET', '**/api/moodboard/mock-board-id', (req) => {
      // Force it to match what we expect in Journey 1
      req.reply({ statusCode: 200, body: { ...mockBoardState, title: 'My UI Test Board' } });
    }).as('getBoard');

    cy.visit('/auth?mode=login');
    cy.get('input[id="email"]').type('test@example.com');
    cy.get('input[id="password"]').type('password123');
    cy.get('button[type="submit"]').click();
    
    cy.wait('@loginRequest');
    
    // Store token in localStorage to ensure it's available for all tests
    cy.window().then((win) => {
      win.localStorage.setItem('accessToken', mockJwt);
    });
    
    // Check if we reached dashboard and wait for network
    cy.location('pathname', { timeout: 10000 }).should('include', '/dashboard');
  });

  it('Journey 1: Create, Duplicate, Crop Enter/Exit, Shadow, Mirror, Delete, Save, Reload', () => {
    // 1. Create New Moodboard
    cy.contains(/Create New/i).click({ force: true });
    cy.wait(4000); // Give the full canvas routing time to load and display
    cy.get('canvas', { timeout: 15000 }).should('be.visible');
    
    // Must save first to be able to upload images as per application logic
    cy.get('button[title="Save"]').click();
    cy.get('.ant-modal').should('be.visible');
    cy.get('.ant-modal').find('input').clear().type('My UI Test Board');
    cy.get('.ant-modal').contains('button', /Save/i).click();
    
    cy.contains('Moodboard saved.').should('be.visible');
    cy.url().should('include', '/mock-board-id');
    
    // 2. Uploading Image from file
    cy.insertImageViaExplorer('cypress/fixtures/test-image.jpg');
    
    // Extra wait to ensure image is fully rendered and ready for interaction
    cy.wait(2000);
    
    const canvas = () => cy.get('canvas').first();
    const selectImage = () => {
      canvas().then(($canvas) => {
        const rect = $canvas[0].getBoundingClientRect();
        const offsetX = rect.width / 2;
        const offsetY = rect.height / 2;
        const clientX = rect.left + offsetX;
        const clientY = rect.top + offsetY;

        cy.wrap($canvas[0]).trigger('mousedown', {
          clientX, clientY, offsetX, offsetY,
          button: 0, force: true, bubbles: true, cancelable: true
        })
        .trigger('mouseup', {
          clientX, clientY, offsetX, offsetY,
          button: 0, force: true, bubbles: true, cancelable: true
        });
      });
    };
    
    // Verify selection is actually visible by checking for visual indicators
    const verifySelection = () => {
      canvas().should('be.visible');
      cy.wait(200);
    };

    // 3. Image properties toolbar actions (Cypress scope)
    // 3a. Duplicate
    selectImage();
    verifySelection();
    cy.get('button[title="Duplicate"]').should('exist').click({ force: true });
    cy.wait(800);

    // 3b. Shadow
    selectImage();
    verifySelection();
    cy.get('button[title="Shadow"], button[title="Add shadow"], button[aria-label="Shadow"]').should('exist').click({ force: true });
    cy.wait(600);
    
    // 3c. Crop (enter + apply)
    selectImage();
    verifySelection();
    cy.get('img[alt="Crop"], button[title="Crop"]').first().should('exist').click({ force: true });
    cy.wait(500);
    cy.get('body').type('{enter}', { force: true });
    cy.wait(600);
    
    // 3d. Mirror
    selectImage();
    verifySelection();
    cy.get('button[title="Mirror"], button[title="Flip"], button[aria-label*="Flip"]').should('exist').click({ force: true });
    cy.wait(600);

    // 3e. Forward + Backward
    selectImage();
    verifySelection();
    cy.get('button[title="Forward"]').should('exist').click({ force: true });
    cy.wait(300);
    cy.get('button[title="Backward"]').should('exist').click({ force: true });
    cy.wait(300);

    // 3f. Delete
    selectImage();
    verifySelection();
    cy.get('button[title="Delete"], button[aria-label="Delete"]').should('exist').click({ force: true });
    cy.wait(700);
    
    // 9. Save Board
    cy.get('button[title="Save"]').click({ force: true });
    cy.get('.ant-modal').contains('button', /Save/i).click();
    
    // Wait for the save operation to complete before reloading
    cy.contains('Moodboard saved.').should('be.visible');

    // 10. Reload and Verify
    cy.reload();
    cy.get('canvas').should('be.visible');
    // Verify the name got changed
    cy.get('input[aria-label="Project name"]').should('have.value', 'My UI Test Board');
  });

 

  it('Journey 2: Pinterest Image Adding Test', () => {
    // 1. Initial State: Not Connected
    cy.intercept('GET', '**/api/integrations/pinterest/status', {
      statusCode: 200,
      body: {
        connected: false
      }
    }).as('pinterestStatusDisconnected');

    // Mock Pinterest Connect API
    cy.intercept('GET', '**/api/integrations/pinterest/auth-url', {
      statusCode: 200,
      body: {
        authUrl: 'http://localhost:3000/mock-pinterest-auth'
      }
    }).as('pinterestAuthUrl');

    cy.intercept('GET', '**/api/integrations/pinterest/boards', {
      statusCode: 200,
      body: {
        boards: [
          { id: 'board-1', name: 'Home Decor', description: 'Interior design ideas', imageUrl: null },
          { id: 'board-2', name: 'Fashion', description: 'Style inspiration', imageUrl: null }
        ]
      }
    }).as('pinterestBoards');

    cy.intercept('GET', '**/api/integrations/pinterest/boards/board-1/pins', {
      statusCode: 200,
      body: {
        pins: [
          { id: 'pin-1', title: 'Modern Bedroom', image_url: 'https://i.pinimg.com/564x/test-image.jpg', url: 'https://pinterest.com' }
]
      }
    }).as('pinterestPins');

    // Intercept the direct thumbnail requests so they show up in the Pinterest sidebar
    cy.intercept('GET', 'https://i.pinimg.com/564x/test-image.jpg', {
      statusCode: 200,
      fixture: 'test-image.jpg',
      headers: {
        'Content-Type': 'image/jpeg',
        'Access-Control-Allow-Origin': '*'
      }
    }).as('pinterestThumbnail');

    // Intercept the proxy request when "Add" is pressed, using the test-image fixture
    cy.intercept('GET', '**/api/proxy/media/pinterest*', {
      statusCode: 200,
      fixture: 'test-image.jpg',
      headers: {
        'Content-Type': 'image/jpeg',
        'Access-Control-Allow-Origin': '*'
      }
    }).as('pinterestProxy');

    cy.visit('/dashboard/moodboards/mock-board-id');
    cy.get('canvas', { timeout: 10000 }).should('be.visible');
    
    // 2. Open Pinterest View
    cy.get('nav[role="tablist"]').contains('button', /Pinterest/i).click({ force: true });
    cy.wait('@pinterestStatusDisconnected');

    // 3. Connect to Pinterest
    // Setup a mock for window.open to simulate popup behavior
    cy.window().then((win) => {
      cy.stub(win, 'open').callsFake(() => {
        // Automatically send the success message to simulate completing the auth flow
        setTimeout(() => {
          win.postMessage({ type: 'PINTEREST_AUTH_SUCCESS' }, '*');
        }, 500);
        return { closed: false, close: cy.stub() }; // Mock popup window object
      }).as('windowOpen');
    });

    // Update status mock for the subsequent check after connect
    cy.intercept('GET', '**/api/integrations/pinterest/status', {
      statusCode: 200,
      body: {
        connected: true,
        integration: {
          id: 'pinterest-user-123',
          username: 'test_user',
          accessToken: 'test-token'
        }
      }
    }).as('pinterestStatusConnected');

    // Click "Connect" button and wait for auth URL to be fetched
    cy.contains('button', /Connect/i).click({ force: true });
    cy.wait('@pinterestAuthUrl');
    cy.get('@windowOpen').should('have.been.calledOnce');

    // Wait for the post-connect status fetch
    cy.wait('@pinterestStatusConnected');
    cy.contains('Pinterest connected successfully!').should('be.visible');

    // 4. Verify Pinterest boards load
    cy.wait('@pinterestBoards');
    cy.contains('Home Decor').should('be.visible');

    // 4.5. Test Refresh Boards Button
    cy.contains('button', /Refresh/i).should('be.visible').click({ force: true });
    cy.wait('@pinterestBoards');
    cy.contains('Refreshed boards').should('be.visible');

    // 5. Click a board to view pins
    cy.contains('Home Decor').click({ force: true });
    cy.wait('@pinterestPins');

    // 6. Wait for pins to render, find the "Modern Bedroom" pin, and click its "Add" button
    cy.contains('Modern Bedroom')
      .parents('[class*="border"], [class*="card"], div') // Finds the pin container
      .first()
      .contains('button', /Add/i)
      .should('be.visible')
      .click({ force: true });
    
    // 7. Wait for image to be added to the board
    cy.wait(2000); // Give time for image to load and add to canvas

    // 8. Verify image was added to canvas (smoke check for toolbar to confirm selection of newly added image)
    const selectImage = () => {
      cy.get('canvas').first().then(($canvas) => {
        const rect = $canvas[0].getBoundingClientRect();
        const offsetX = rect.width / 2;
        const offsetY = rect.height / 2;
        const clientX = rect.left + offsetX;
        const clientY = rect.top + offsetY;
        
        cy.wrap($canvas[0]).trigger('mousedown', { 
          clientX, clientY, offsetX, offsetY,
          button: 0, force: true, bubbles: true, cancelable: true
        })
        .trigger('mouseup', { 
          clientX, clientY, offsetX, offsetY,
          button: 0, force: true, bubbles: true, cancelable: true
        });
      });
    };
    
    // Newly added items are often placed at the center, so selecting the center should bring up the item toolbar if it's there
    selectImage();
    cy.get('button[title="Shadow"], button[title="Mirror"], button[title="Delete"]').should('exist');

    // 9. Disconnect Pinterest
    cy.intercept('POST', '**/api/integrations/pinterest/disconnect', {
      statusCode: 200,
      body: { success: true }
    }).as('pinterestDisconnect');

    // Update status mock to return disconnected before clicking disconnect
    cy.intercept('GET', '**/api/integrations/pinterest/status', {
      statusCode: 200,
      body: {
        connected: false
      }
    }).as('pinterestStatusDisconnectedAgain');

    cy.contains('button', /Disconnect/i).should('exist').click({ force: true });
    cy.wait('@pinterestDisconnect');
    
    cy.wait('@pinterestStatusDisconnectedAgain'); // The view re-fetches status on disconnect

    cy.contains('Pinterest disconnected successfully').should('be.visible');

    // 10. Verify Connect button reappears
    cy.contains('button', /Connect/i).should('be.visible');

    // 11. Save to persist the Pinterest image
    cy.get('button[title="Save"]').click({ force: true });
    cy.get('.ant-modal').contains('button', /Save/i).click();
    cy.contains('Moodboard saved.').should('be.visible');
  });

  it('Journey 3: Drawing with Pen - Draw a Simple Line', () => {
    // Navigate to moodboard
    cy.visit('/dashboard/moodboards/mock-board-id');
    cy.get('canvas', { timeout: 10000 }).should('be.visible');

    const canvas = () => cy.get('canvas').first();

    // 1. Click "Add drawing" button to enter draw mode
    cy.get('button[title="Add drawing"]').should('exist').click({ force: true });
    cy.wait(300);

    // 2. Draw a simple line on the canvas
    canvas().then(($canvas) => {
      const rect = $canvas[0].getBoundingClientRect();
      const startOffsetX = rect.width * 0.25;
      const startOffsetY = rect.height * 0.40;
      const endOffsetX = rect.width * 0.45;
      const endOffsetY = rect.height * 0.52;

      const startClientX = rect.left + startOffsetX;
      const startClientY = rect.top + startOffsetY;
      const endClientX = rect.left + endOffsetX;
      const endClientY = rect.top + endOffsetY;

      cy.wrap($canvas[0])
        .trigger('mousedown', {
          clientX: startClientX,
          clientY: startClientY,
          offsetX: startOffsetX,
          offsetY: startOffsetY,
          button: 0,
          force: true,
          bubbles: true,
          cancelable: true,
        })
        .trigger('mousemove', {
          clientX: endClientX,
          clientY: endClientY,
          offsetX: endOffsetX,
          offsetY: endOffsetY,
          force: true,
          bubbles: true,
          cancelable: true,
        })
        .trigger('mouseup', {
          clientX: endClientX,
          clientY: endClientY,
          offsetX: endOffsetX,
          offsetY: endOffsetY,
          button: 0,
          force: true,
          bubbles: true,
          cancelable: true,
        });
    });
    cy.wait(300);

    // 3. Exit drawing mode via Escape
    cy.get('body').type('{esc}', { force: true });
    cy.wait(300);

    // 4. Save board and verify toast
    cy.get('button[title="Save"]').click({ force: true });
    cy.get('.ant-modal').contains('button', /Save/i).click();
    cy.contains('Moodboard saved.').should('be.visible');

    // 5. Reload and verify board persists
    cy.reload();
    cy.get('canvas', { timeout: 10000 }).should('be.visible');
  });

  it('Journey 4: Background Color Change - Select Color via Hexcode', () => {
    // Navigate to moodboard
    cy.visit('/dashboard/moodboards/mock-board-id');
    cy.get('canvas', { timeout: 10000 }).should('be.visible');

    // 1. Click "Background" button to enter background edit mode
    cy.get('button[title="Background"]').should('exist').click({ force: true });
    cy.wait(300);

    // 2. Select color via hexcode input
    // The color input should be visible after clicking Background
    cy.get('input[type="color"]').should('be.visible').first().invoke('val', '#f4efe6').trigger('input').trigger('change');
    cy.wait(300);

    // 3. Click "Done" button to apply background change
    cy.contains('button', /^Done$/).click({ force: true });
    cy.wait(300);

    // 4. Save board and verify toast
    cy.get('button[title="Save"]').click({ force: true });
    cy.get('.ant-modal').contains('button', /Save/i).click();
    cy.contains('Moodboard saved.').should('be.visible');

    // 5. Reload and verify board persists with new background
    cy.reload();
    cy.get('canvas', { timeout: 10000 }).should('be.visible');
  });

  it('Journey 5: Text Box Change - Insert Text Box and Type Sample Text', () => {
    // Navigate to moodboard
    cy.visit('/dashboard/moodboards/mock-board-id');
    cy.get('canvas', { timeout: 10000 }).should('be.visible');
    
    // Wait for the board and all tools to fully load and settle FIRST
    cy.wait(4000);

    const canvas = () => cy.get('canvas').first();

    // 1. Click "Add text" button (T) to insert text box
    cy.get('button[title="Add text"]').first().should('exist').click({ force: true });
    cy.wait(2000); // Wait for text box to be fully added

    // 2. Double click the newly created text (which is placed in the center of the board)
    canvas().then(($canvas) => {
      const rect = $canvas[0].getBoundingClientRect();
      const offsetX = rect.width / 2;
      const offsetY = rect.height / 2;
      const clientX = rect.left + offsetX;
      const clientY = rect.top + offsetY;

      const evtProps = {
        clientX,
        clientY,
        offsetX,
        offsetY,
        button: 0,
        force: true,
        bubbles: true,
        cancelable: true,
      };

      // Konva detects double click using two rapid down/up pairs
      cy.wrap($canvas[0])
        .trigger('mousedown', evtProps)
        .trigger('mouseup', evtProps)
        .trigger('mousedown', evtProps)
        .trigger('mouseup', evtProps)
        .trigger('dblclick', evtProps); // Fire native dblclick as fallback
    });
    cy.wait(1000); // Wait for the textarea to render

    // 3. Type the sample text into the textarea
    cy.get('textarea').last().should('exist').clear({ force: true }).type('Sample Text', { force: true });
    cy.wait(1000); // Don't rush, wait to see the typed text

    // 4. Exit edit mode by pressing Escape
    cy.get('textarea').last().type('{esc}', { force: true });
    cy.wait(1000);

    // 5. Save board and verify toast
    cy.get('button[title="Save"]').first().click({ force: true });
    cy.get('.ant-modal').last().contains('button', /Save/i).click({ force: true });
    cy.contains('Moodboard saved.').should('be.visible');

    // 6. Reload and verify board persists with text
    cy.reload();
    cy.get('canvas', { timeout: 10000 }).should('be.visible');
  });
});
